  "privacy.section3.li2": { de: "Abwicklung von Transaktionen und Kommunikation (Art. 6 Abs. 1 lit. b DSGVO)", it: "Elaborazione di transazioni e comunicazioni (Art. 6 comma 1 lett. b GDPR)", en: "Processing of transactions and communication (Art. 6 para. 1 lit. b GDPR)", fr: "Traitement des transactions et communication (Art. 6 par. 1 lit. b RGPD)", pl: "Przetwarzanie transakcji i komunikacji (Art. 6 ust. 1 lit. b RODO)", tr: "İşlemlerin ve iletişimin işlenmesi (Madde 6 fıkra 1 bent b GDPR)", uk: "Обробка транзакцій та комунікацій (Ст. 6 п. 1 літ. b GDPR)" },
  "privacy.section3.li3": { de: "Erfüllung gesetzlicher Pflichten, insbesondere steuerrechtlicher Vorgaben (Art. 6 Abs. 1 lit. c DSGVO)", it: "Adempimento di obblighi legali, in particolare fiscali (Art. 6 comma 1 lett. c GDPR)", en: "Fulfillment of legal obligations, especially tax requirements (Art. 6 para. 1 lit. c GDPR)", fr: "Respect des obligations légales, notamment fiscales (Art. 6 par. 1 lit. c RGPD)", pl: "Wypełnianie obowiązków prawnych, w szczególności podatkowych (Art. 6 ust. 1 lit. c RODO)", tr: "Yasal yükümlülüklerin yerine getirilmesi, özellikle vergi gereksinimleri (Madde 6 fıkra 1 bent c GDPR)", uk: "Виконання юридичних зобов'язань, особливо податкових вимог (Ст. 6 п. 1 літ. c GDPR)" },
  "privacy.section3.li4": { de: "Sicherheit, Betrugsprävention und Missbrauchserkennung (Art. 6 Abs. 1 lit. f DSGVO)", it: "Sicurezza, prevenzione frodi e rilevamento abusi (Art. 6 comma 1 lett. f GDPR)", en: "Security, fraud prevention and abuse detection (Art. 6 para. 1 lit. f GDPR)", fr: "Sécurité, prévention de la fraude et détection d'abus (Art. 6 par. 1 lit. f RGPD)", pl: "Bezpieczeństwo, zapobieganie oszustwom i wykrywanie nadużyć (Art. 6 ust. 1 lit. f RODO)", tr: "Güvenlik, dolandırıcılık önleme ve kötüye kullanım tespiti (Madde 6 fıkra 1 bent f GDPR)", uk: "Безпека, запобігання шахрайству та виявлення зловживань (Ст. 6 п. 1 літ. f GDPR)" },
